#include<bits/stdc++.h>using namespace std;int n,q,a[1000010],b[1000010],ans=0;int check(int x){	int cnt=0;	for(int i=1;i<=n;i++){		if(a[i]<=x) cnt++;	}	for(int i=1;i<=q;i++){		if(b[i]>=1&&b[i]<=n){			if(b[i]<=x) cnt++;		}else if(b[i]<0){			if(abs(b[i])<=cnt) cnt--;		}	}	return cnt;}int main(){	cin>>n>>q;	int cnt1=n,cnt2=0;	for(int i=1;i<=n;i++) scanf("%d",&a[i]);	for(int i=1;i<=q;i++){		scanf("%d",&b[i]);		if(b[i]<0) cnt2++;		else if(b[i]>=1&&b[i]<=n) cnt1++;	}	if(cnt1==cnt2){		cout<<0;		return 0;	}	int l=1,r=n,mid=(l+r)/2;	while(l<r){		if(!check(mid)) l=mid+1;		else r=mid;		mid=(l+r)/2;	}	cout<<mid;		return 0;}